  1→import { useEffect, useRef, useState } from 'react';
  2→import './mobilenavlink.css';
  3→import { motion } from 'framer-motion';
  4→import { useAuth } from '../../Context/useAuth';
  5→import { useLocation, useNavigate } from 'react-router-dom';
  6→
  7→const MobileNavlink = () => {
  8→    const [showNavlinks, setShowNavlinks] = useState(true);
  9→    const timeOutRef = useRef();
 10→    const navigate = useNavigate();
 11→    const location = useLocation();
 12→
 13→    const { session, openAuthModal } = useAuth();
 14→
 15→    const handleNavigatePath = (path) => {
 16→        if (location.pathname === path) {
 17→            return window.location.reload();
 18→        }
 19→        return navigate(path);
 20→    };
 21→
 22→    const activeColor = '#D4A853';
 23→    const inactiveColor = '#787878';
 24→
 25→    const navLinks = [
 26→        {
 27→            type: 'icon',
 28→            label: 'Home',
 29→            path: '/home',
 30→            action: (path) => handleNavigatePath(path),
 31→            icon: (isActive) => (
 32→                <svg xmlns="http://www.w3.org/2000/svg" width="24px" height="24px" viewBox="0 0 24 24" fill={isActive ? activeColor : inactiveColor}>
 33→                    <g clipPath="url(#clip0_1_110)">
 34→                        <path fillRule="evenodd" clipRule="evenodd" d="M14.3594 2.12613C13.0087 0.944612 10.9923 0.94461 9.64162 2.12612L3.2802 7.69086C2.29508 8.55261 1.72998 9.79772 1.72998 11.1066L1.72998 19.1672C1.72998 21.1459 3.33403 22.75 5.31273 22.75L18.6883 22.75C20.667 22.75 22.271 21.1459 22.271 19.1672L22.271 11.1066C22.271 9.79772 21.706 8.55261 20.7208 7.69086L14.3594 2.12613ZM10 16.1136C9.58579 16.1136 9.25 16.4494 9.25 16.8636C9.25 17.2779 9.58579 17.6136 10 17.6136L14 17.6136C14.4142 17.6136 14.75 17.2779 14.75 16.8636C14.75 16.4494 14.4142 16.1136 14 16.1136L10 16.1136Z" fill={isActive ? activeColor : inactiveColor}/>
 35→                    </g>
 36→                </svg>
 37→            ),
 38→        },
 39→        {
 40→            type: 'icon',
 41→            label: 'Explore',
 42→            path: '/home/explore',
 43→            action: (path) => handleNavigatePath(path),
 44→            icon: (isActive) => (
 45→                <svg xmlns="http://www.w3.org/2000/svg" width="24px" height="24px" viewBox="0 0 24 24" fill={isActive ? activeColor : inactiveColor}>
 46→                    <path
 47→                        fillRule="evenodd"
 48→                        d="M12,2 C17.5228475,2 22,6.4771525 22,12 C22,17.5228475 17.5228475,22 12,22 C6.4771525,22 2,17.5228475 2,12 C2,6.4771525 6.4771525,2 12,2 Z M17.9842695,7.39078625 C18.1985588,6.64477525 17.4973604,5.9435768 16.7513494,6.1578661 L16.6494246,6.19284365 L9.57835679,9.02127078 L9.47282273,9.07079854 C9.30957453,9.15937167 9.17428758,9.29167162 9.08209683,9.45256344 L9.02127078,9.57835679 L6.19284365,16.6494246 L6.1578661,16.7513494 C5.9435768,17.4973604 6.64477525,18.1985588 7.39078625,17.9842695 L7.49271102,17.949292 L14.5637788,15.1208648 L14.6693129,15.0713371 C14.8325611,14.982764 14.967848,14.850464 15.0600388,14.6895722 L15.1208648,14.5637788 L17.949292,7.49271102 L17.9842695,7.39078625 Z M12,10 C13.1045695,10 14,10.8954305 14,12 C14,13.1045695 13.1045695,14 12,14 C10.8954305,14 10,13.1045695 10,12 C10,10.8954305 10.8954305,10 12,10 Z"
 49→                    />
 50→                </svg>
 51→            ),
 52→        },
 53→    ];
 54→
 55→    useEffect(() => {
 56→        const scroll = () => {
 57→            setShowNavlinks(false);
 58→
 59→            if (timeOutRef.current) {
 60→                clearTimeout(timeOutRef.current);
 61→            }
 62→
 63→            timeOutRef.current = setTimeout(() => {
 64→                setShowNavlinks(true);
 65→            }, 500);
 66→        };
 67→
 68→        document.addEventListener('scroll', scroll, true);
 69→        return () => {
 70→            if (timeOutRef.current) {
 71→                clearTimeout(timeOutRef.current);
 72→            }
 73→            document.removeEventListener('scroll', scroll, true);
 74→        };
 75→    }, []);
 76→
 77→    return (
 78→        <>
 79→            {showNavlinks && (
 80→                <motion.div
 81→                    initial={{ opacity: 0, y: 10 }}
 82→                    animate={{ opacity: 1, y: 0, transition: { type: 'spring', stiffness: 300, damping: 25, mass: 0.8 } }}
 83→                    exit={{ opacity: 0, y: 20, transition: { duration: 0.2, ease: 'easeOut' } }}
 84→                    className="mobile-navlink-container"
 85→                >
 86→                    <div className="mobile-navlink-icon-container">
 87→                        {navLinks.map((link, index) => {
 88→                            const isActive = link.path && location.pathname === link.path;
 89→
 90→                            return (
 91→                                <div
 92→                                    key={index}
 93→                                    className="mobile-navlink-item"
 94→                                    onClick={() => link.action(link.path)}
 95→                                >
 96→                                    <div className="mobile-navlink-icons">
 97→                                        {link.icon(isActive)}
 98→                                    </div>
 99→                                    <p className={`mobile-navlink-label ${isActive ? 'mobile-navlink-label-active' : ''}`}>
100→                                        {link.label}
101→                                    </p>
102→                                    {isActive && <div className="mobile-navlink-active-dot" />}
103→                                </div>
104→                            );
105→                        })}
106→                    </div>
107→                </motion.div>
108→            )}
109→        </>
110→    );
111→};
112→
113→export default MobileNavlink;
