 78→    .mobile-navlink-icons svg{
 79→        transition: transform 0.2s ease;
 80→    }
 81→    .mobile-navlink-item:active .mobile-navlink-icons svg{
 82→        transform: scale(0.9);
 83→    }
 84→
 85→    /* ── Nav label ── */
 86→    .mobile-navlink-label{
 87→        font-family: var(--font-ui, sans-serif);
 88→        font-size: 0.54rem;
 89→        font-weight: 600;
 90→        letter-spacing: 0.01rem;
 91→        color: var(--text-faint, #999);
 92→        margin: 0;
 93→        padding: 0;
 94→        transition: color 0.2s ease;
 95→        white-space: nowrap;
 96→    }
 97→    .mobile-navlink-label-active{
 98→        color: #D4A853;
 99→    }
100→}
